import{_ as a,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2015年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2015年/核心总结.md","filePath":"01_letters/2015年/核心总结.md"}'),t={name:"01_letters/2015年/核心总结.md"};function o(h,l,u,n,d,s){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="_2015年巴菲特致股东信核心总结" tabindex="-1">2015年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2015年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2015年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长6.4%，股价下跌12.5%</li><li>标普500上涨1.4%</li><li>51年复合年增长率19.2%</li><li>首次网络直播股东大会</li></ul><h2 id="关键理念更新" tabindex="-1">关键理念更新 <a class="header-anchor" href="#关键理念更新" aria-label="Permalink to &quot;关键理念更新&quot;">​</a></h2><h3 id="内在价值计算改进" tabindex="-1">内在价值计算改进 <a class="header-anchor" href="#内在价值计算改进" aria-label="Permalink to &quot;内在价值计算改进&quot;">​</a></h3><ul><li>首次将保险承保收入纳入业务收益计算</li><li>每股现金和投资：159,794美元</li><li>业务收益（含承保）：每股12,304美元</li><li>过去十年每股年度承保收入平均1,434美元</li></ul><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="连续13年承保盈利" tabindex="-1">连续13年承保盈利 <a class="header-anchor" href="#连续13年承保盈利" aria-label="Permalink to &quot;连续13年承保盈利&quot;">​</a></h3><ul><li>累计262亿美元税前收益</li><li>浮存金增至877亿美元</li></ul><h3 id="bhsi的成长" tabindex="-1">BHSI的成长 <a class="header-anchor" href="#bhsi的成长" aria-label="Permalink to &quot;BHSI的成长&quot;">​</a></h3><ul><li>成立不到三年，年保费量10亿美元</li><li>Peter Eastwood领导</li><li>必将成为全球领先的财险公司之一</li></ul><h2 id="受监管业务表现" tabindex="-1">受监管业务表现 <a class="header-anchor" href="#受监管业务表现" aria-label="Permalink to &quot;受监管业务表现&quot;">​</a></h2><h3 id="bhe-伯克希尔哈撒韦能源" tabindex="-1">BHE（伯克希尔哈撒韦能源） <a class="header-anchor" href="#bhe-伯克希尔哈撒韦能源" aria-label="Permalink to &quot;BHE（伯克希尔哈撒韦能源）&quot;">​</a></h3><ul><li>爱荷华州电价16年未上涨，同期行业上涨44%</li><li>风电占零售销售的55%，2020年将达89%</li><li>爱荷华州是美国的&quot;沙特阿拉伯&quot;（风电）</li></ul><h3 id="bnsf" tabindex="-1">BNSF <a class="header-anchor" href="#bnsf" aria-label="Permalink to &quot;BNSF&quot;">​</a></h3><ul><li>每吨英里收入约3美分，其他铁路4-5美分</li><li>每加仑柴油运送一吨货物500英里</li><li>铁路能效是卡车的四倍</li></ul><h2 id="生产力与繁荣" tabindex="-1">生产力与繁荣 <a class="header-anchor" href="#生产力与繁荣" aria-label="Permalink to &quot;生产力与繁荣&quot;">​</a></h2><h3 id="农业革命" tabindex="-1">农业革命 <a class="header-anchor" href="#农业革命" aria-label="Permalink to &quot;农业革命&quot;">​</a></h3><ul><li>1900年：40%劳动力从事农业</li><li>现在：2%劳动力生产更多粮食</li><li>生产力提升释放人力到其他领域</li></ul><h3 id="铁路效率" tabindex="-1">铁路效率 <a class="header-anchor" href="#铁路效率" aria-label="Permalink to &quot;铁路效率&quot;">​</a></h3><ul><li>1947年：135万员工，6,550亿吨英里</li><li>2014年：18.7万员工，1.85万亿吨英里</li><li>实际运价下降55%</li></ul><h3 id="geico的成本革命" tabindex="-1">GEICO的成本革命 <a class="header-anchor" href="#geico的成本革命" aria-label="Permalink to &quot;GEICO的成本革命&quot;">​</a></h3><ul><li>代理模式：40美分费用/1美元保费</li><li>州立农业/好事达：约25美分</li><li>USAA/GEICO：约14-15美分</li><li>2015年保费226亿美元，市场份额11.4%</li></ul><h2 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h2><h3 id="主要持股" tabindex="-1">主要持股 <a class="header-anchor" href="#主要持股" aria-label="Permalink to &quot;主要持股&quot;">​</a></h3><ul><li>富国银行（9.8%）、可口可乐（9.3%）、IBM（8.4%）、美国运通（15.6%）</li><li>新增苹果（1.1%）、达美航空（7.5%）、西南航空（7.0%）</li><li>美国银行优先股+认股权证价值118亿美元</li></ul><h3 id="卡夫亨氏" tabindex="-1">卡夫亨氏 <a class="header-anchor" href="#卡夫亨氏" aria-label="Permalink to &quot;卡夫亨氏&quot;">​</a></h3><ul><li>伯克希尔持股27%</li><li>权益法核算，GAAP价值153亿美元</li><li>成本基础98亿美元</li></ul><h2 id="关键投资理念" tabindex="-1">关键投资理念 <a class="header-anchor" href="#关键投资理念" aria-label="Permalink to &quot;关键投资理念&quot;">​</a></h2><h3 id="投资的简单公式" tabindex="-1">投资的简单公式 <a class="header-anchor" href="#投资的简单公式" aria-label="Permalink to &quot;投资的简单公式&quot;">​</a></h3><ul><li>A组（主动投资者）+ B组（被动投资者）= 整个投资宇宙</li><li>B组注定获得平均结果</li><li>A组也必须获得平均结果</li><li>哪组成本更低，哪组就获胜</li></ul><h3 id="费用的巨大影响" tabindex="-1">费用的巨大影响 <a class="header-anchor" href="#费用的巨大影响" aria-label="Permalink to &quot;费用的巨大影响&quot;">​</a></h3><ul><li>主动投资者承担更高成本</li><li>对冲基金&quot;2和20&quot;收费模式</li><li>基金中的基金叠加费用</li><li>九年间，五只基金中的基金平均年化2.2%</li><li>标普500基金年化7.1%</li></ul><h3 id="对富人的建议悖论" tabindex="-1">对富人的建议悖论 <a class="header-anchor" href="#对富人的建议悖论" aria-label="Permalink to &quot;对富人的建议悖论&quot;">​</a></h3><ul><li>富人习惯获得&quot;额外&quot;的东西</li><li>金融产品对穷人和富人一样有效</li><li>富人不情愿使用大众产品</li><li>过去十年浪费超过1,000亿美元</li></ul><h2 id="制造业表现" tabindex="-1">制造业表现 <a class="header-anchor" href="#制造业表现" aria-label="Permalink to &quot;制造业表现&quot;">​</a></h2><ul><li>税后回报率18.4%</li><li>净有形资产256亿美元</li><li>Clayton Homes成为美国最大房屋建筑商</li><li>Marmon铁路车队扩展至133,220辆</li></ul><h2 id="重要风险" tabindex="-1">重要风险 <a class="header-anchor" href="#重要风险" aria-label="Permalink to &quot;重要风险&quot;">​</a></h2><h3 id="大规模破坏性攻击" tabindex="-1">大规模破坏性攻击 <a class="header-anchor" href="#大规模破坏性攻击" aria-label="Permalink to &quot;大规模破坏性攻击&quot;">​</a></h3><ul><li>网络、生物、核或化学攻击</li><li>伯克希尔与美国企业共享的风险</li><li>一年内概率小，长期接近确定</li><li>爱因斯坦：&quot;我不知道第三次世界大战用什么武器，但第四次将用棍棒和石头&quot;</li></ul><h3 id="气候变化" tabindex="-1">气候变化 <a class="header-anchor" href="#气候变化" aria-label="Permalink to &quot;气候变化&quot;">​</a></h3><ul><li>作为公民应关注</li><li>作为保险公司股东不必担心</li><li>保险合同每年重新定价反映风险变化</li><li>若超级巨灾增多，保险业务可能更大更盈利</li></ul><h2 id="房地产市场" tabindex="-1">房地产市场 <a class="header-anchor" href="#房地产市场" aria-label="Permalink to &quot;房地产市场&quot;">​</a></h2><h3 id="clayton-homes的抵押贷款实践" tabindex="-1">Clayton Homes的抵押贷款实践 <a class="header-anchor" href="#clayton-homes的抵押贷款实践" aria-label="Permalink to &quot;Clayton Homes的抵押贷款实践&quot;">​</a></h3><ul><li>100%风险保留</li><li>平均贷款59,942美元</li><li>月供平均522美元</li><li>止赎率2.64%，但95.4%借款人按时还款</li><li>监管审查：65次，罚款仅38,200美元</li></ul><h2 id="企业文化特点" tabindex="-1">企业文化特点 <a class="header-anchor" href="#企业文化特点" aria-label="Permalink to &quot;企业文化特点&quot;">​</a></h2><ul><li>25人总部管理361,270名员工</li><li>2015年无人加入无人离开</li><li>就业稳定性独特</li><li>从未有过&quot;重组&quot;费用</li></ul><h2 id="杰克·博格尔的贡献" tabindex="-1">杰克·博格尔的贡献 <a class="header-anchor" href="#杰克·博格尔的贡献" aria-label="Permalink to &quot;杰克·博格尔的贡献&quot;">​</a></h2><ul><li>几十年呼吁低成本指数基金</li><li>帮助数百万投资者获得更好回报</li><li>应该为他竖立雕像</li><li>&quot;投资管理从创新者到模仿者再到蜂拥而至的无能者&quot;</li></ul><h2 id="美国经济展望" tabindex="-1">美国经济展望 <a class="header-anchor" href="#美国经济展望" aria-label="Permalink to &quot;美国经济展望&quot;">​</a></h2><ul><li>240年间美国人创造90万亿美元财富</li><li>市场体系出色配置资本、智慧和劳动力</li><li>今天出生的婴儿是历史上最幸运的一代</li><li>偶尔会有市场下跌甚至恐慌，但财富积累不会停止</li></ul>',51)])])}const b=a(t,[["render",o]]);export{q as __pageData,b as default};
